const results = {};

for (const item of items) {
  const doc = item.json;
  const matchId = doc.Match_ID;
  const name = (doc.Document_name || "").toUpperCase();

  if (!results[matchId]) {
    results[matchId] = {
      Match_ID:        matchId,
      "Booking#":      doc["Booking#"]      || "N/A",
      "Booking type":  doc["Booking type"]  || "N/A",
      "Folder name":   doc["Folder name"]   || "N/A",
      Parent_ID:       doc.Parent_ID        || null,
      Child_ID:        doc.Child_ID         || matchId,
      Document_ID:     null,
      Document_name:   "No BL available",
      "BL_available?": "no",
      priority: 0
    };
  }

  let currentPriority = 0;

  if (name.includes("TR")) {
    currentPriority = 4;
  } else if (name.includes("HBL")) {
    currentPriority = 3;
  } else if (name.includes("BL") && !name.includes("DRAFT")) {
    currentPriority = 2;
  } else if (name.includes("DRAFT")) {
    currentPriority = 1;
  }

  if (currentPriority > results[matchId].priority) {
    results[matchId].Document_ID    = doc.Document_ID;
    results[matchId].Document_name  = doc.Document_name;
    results[matchId].priority       = currentPriority;
    results[matchId]["BL_available?"] = "yes";
  }
}

return Object.values(results).map(res => {
  const { priority, ...cleanResult } = res;
  return { json: cleanResult };
});

const results = {};

for (const item of items) {
  const doc = item.json;
  const matchId = doc.Match_ID;
  const name = (doc.Document_name || "").toUpperCase();

  if (!results[matchId]) {
    results[matchId] = {
      Match_ID:        matchId,
      "Booking#":      doc["Booking#"]      || "N/A",
      "Booking type":  doc["Booking type"]  || "N/A",
      "Folder name":   doc["Folder name"]   || "N/A",
      Parent_ID:       doc.Parent_ID        || null,
      Child_ID:        doc.Child_ID         || matchId,
      Document_ID:     null,
      Document_name:   "No PL available",
      "PL_available?": "no",
      priority: 0
    };
  }

  let currentPriority = 0;

  if (name.includes("PL") && !name.includes("DRAFT") && !name.includes("CI")) {
    currentPriority = 3;
  } else if (name.includes("PL") && !name.includes("DRAFT") && name.includes("CI")) {
    currentPriority = 2;
  } else if (name.includes("PL") && name.includes("DRAFT")) {
    currentPriority = 1;
  }

  if (currentPriority > results[matchId].priority) {
    results[matchId].Document_ID    = doc.Document_ID;
    results[matchId].Document_name  = doc.Document_name;
    results[matchId].priority       = currentPriority;
    results[matchId]["PL_available?"] = "yes";
  }
}

return Object.values(results).map(res => {
  const { priority, ...cleanResult } = res;
  return { json: cleanResult };
});

const getVal = (obj, path, fallback = 0) => {
  return path.split('.').reduce((acc, part) => acc && acc[part], obj) ?? fallback;
};

const workflowStart = new Date($('Start_Time').first().json.Workflow_Start);
const runtime = ((new Date() - workflowStart) / 1000).toFixed(1);

const STOP_WORDS = new Set(['the','and','of','for','a','an','in','to','with','by','at','from','on','is','are','as']);

const getKeywords = (str) => {
  return str
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 1 && !STOP_WORDS.has(w));
};

const fieldOverlap = (blVal, plVal, label) => {
  if (!blVal || !plVal || blVal === 'NOT_FOUND' || plVal === 'NOT_FOUND') {
    return { status: '⚠️ UNAVAILABLE', detail: `${label} missing on BL or PL` };
  }
  const blWords = getKeywords(blVal);
  const plWords = new Set(getKeywords(plVal));
  if (blWords.length === 0) {
    return { status: '⚠️ UNAVAILABLE', detail: `BL ${label} could not be parsed` };
  }
  const matched = blWords.filter(w => plWords.has(w)).length;
  const overlap = matched / blWords.length;
  if (overlap >= 0.6) {
    return { status: '✅ MATCH', detail: `${Math.round(overlap * 100)}% keyword overlap` };
  } else {
    return { status: '❌ DISCREPANCY', detail: `${Math.round(overlap * 100)}% keyword overlap (below 60% threshold)` };
  }
};

const descriptionOverlap = (blDesc, plDesc) => {
  if (!blDesc || !plDesc || blDesc === 'N/A' || plDesc === 'N/A' ||
      blDesc === 'NOT_FOUND' || plDesc === 'NOT_FOUND') {
    return { status: '⚠️ UNAVAILABLE', detail: 'Description missing on BL or PL' };
  }
  const blWords = getKeywords(blDesc);
  const plWords = new Set(getKeywords(plDesc));
  if (blWords.length === 0) {
    return { status: '⚠️ UNAVAILABLE', detail: 'BL description could not be parsed' };
  }
  const matched = blWords.filter(w => plWords.has(w)).length;
  const overlap = matched / blWords.length;
  if (overlap >= 0.6) {
    return { status: '✅ MATCH', detail: `${Math.round(overlap * 100)}% keyword overlap` };
  } else {
    return { status: '❌ DISCREPANCY', detail: `${Math.round(overlap * 100)}% keyword overlap (below 60% threshold)` };
  }
};

// Checks if a string looks like a real container number: 4 letters + 7 digits
const isRealContainerNumber = (str) => {
  return /^[A-Z]{4}\d{7}$/.test((str || '').trim().toUpperCase());
};

return $input.all().map(({ json: input }) => {

  const bl = {
    factory:    input.BL_factory           || {},
    consignee:  input.BL_consignee         || {},
    metrics:    input.BL_logistics_metrics || {},
    containers: (input.BL_containers || []).filter(c => isRealContainerNumber(c.container_number)),
    product:    input.BL_cargo_description || "N/A",
    incoterm:   (input.BL_incoterm_location || "").trim().toUpperCase(),
  };

  const pl = {
    factory:    input.PL_factory           || {},
    consignee:  input.PL_consignee         || {},
    metrics:    input.PL_logistics_metrics || {},
    containers: (input.PL_containers || []).filter(c => isRealContainerNumber(c.container_number)),
    product:    input.PL_cargo_description || "N/A",
    incoterm:   (input.PL_incoterm_location || "").trim().toUpperCase(),
  };

  // ── Check 1: Consignor (name + address) ───────────────────
  const blConsignorName    = (bl.factory.name    || "").trim();
  const plConsignorName    = (pl.factory.name    || "").trim();
  const blConsignorAddress = (bl.factory.address || "").trim();
  const plConsignorAddress = (pl.factory.address || "").trim();

  const consignorNameResult    = fieldOverlap(blConsignorName,    plConsignorName,    'consignor name');
  const consignorAddressResult = fieldOverlap(blConsignorAddress, plConsignorAddress, 'consignor address');

  const consignorErrors   = [];
  const consignorWarnings = [];

  if      (consignorNameResult.status.startsWith('❌'))  consignorErrors.push(`Name: ${consignorNameResult.detail}`);
  else if (consignorNameResult.status.startsWith('⚠️')) consignorWarnings.push(`Name: ${consignorNameResult.detail}`);

  if      (consignorAddressResult.status.startsWith('❌'))  consignorErrors.push(`Address: ${consignorAddressResult.detail}`);
  else if (consignorAddressResult.status.startsWith('⚠️')) consignorWarnings.push(`Address: ${consignorAddressResult.detail}`);

  let consignorStatus;
  if (consignorErrors.length > 0) {
    consignorStatus = `❌ DISCREPANCY (${consignorErrors.join(' | ')})`;
    if (consignorWarnings.length > 0) consignorStatus += ` | ⚠️ ${consignorWarnings.join(', ')}`;
  } else if (consignorWarnings.length > 0) {
    consignorStatus = `⚠️ UNAVAILABLE (${consignorWarnings.join(', ')})`;
  } else {
    consignorStatus = `✅ MATCH`;
  }

  // ── Check 2: Consignee (name + address) ───────────────────
  const blConsigneeName    = (bl.consignee.name    || "").trim();
  const plConsigneeName    = (pl.consignee.name    || "").trim();
  const blConsigneeAddress = (bl.consignee.address || "").trim();
  const plConsigneeAddress = (pl.consignee.address || "").trim();

  const consigneeNameResult    = fieldOverlap(blConsigneeName,    plConsigneeName,    'consignee name');
  const consigneeAddressResult = fieldOverlap(blConsigneeAddress, plConsigneeAddress, 'consignee address');

  const consigneeErrors   = [];
  const consigneeWarnings = [];

  if      (consigneeNameResult.status.startsWith('❌'))  consigneeErrors.push(`Name: ${consigneeNameResult.detail}`);
  else if (consigneeNameResult.status.startsWith('⚠️')) consigneeWarnings.push(`Name: ${consigneeNameResult.detail}`);

  if      (consigneeAddressResult.status.startsWith('❌'))  consigneeErrors.push(`Address: ${consigneeAddressResult.detail}`);
  else if (consigneeAddressResult.status.startsWith('⚠️')) consigneeWarnings.push(`Address: ${consigneeAddressResult.detail}`);

  let consigneeStatus;
  if (consigneeErrors.length > 0) {
    consigneeStatus = `❌ DISCREPANCY (${consigneeErrors.join(' | ')})`;
    if (consigneeWarnings.length > 0) consigneeStatus += ` | ⚠️ ${consigneeWarnings.join(', ')}`;
  } else if (consigneeWarnings.length > 0) {
    consigneeStatus = `⚠️ UNAVAILABLE (${consigneeWarnings.join(', ')})`;
  } else {
    consigneeStatus = `✅ MATCH`;
  }

  // ── Check 3: Gross Weight ─────────────────────────────────
  const blWeight   = getVal(bl, 'metrics.gross_weight_kg');
  const plWeight   = getVal(pl, 'metrics.gross_weight_kg');
  const weightDiff = Math.abs(plWeight - blWeight).toFixed(2);

  let weightStatus;
  if      (blWeight === 0 && plWeight === 0) weightStatus = '⚠️ UNAVAILABLE (missing on both BL and PL)';
  else if (blWeight === 0)                   weightStatus = '⚠️ UNAVAILABLE (missing on BL)';
  else if (plWeight === 0)                   weightStatus = '⚠️ UNAVAILABLE (missing on PL)';
  else if (parseFloat(weightDiff) > 1.0)     weightStatus = `❌ DISCREPANCY (${weightDiff}kg variance)`;
  else                                        weightStatus = '✅ MATCH';

  // ── Check 3b: Volume ──────────────────────────────────────
  const blVolume = getVal(bl, 'metrics.volume_cbm');
  const plVolume = getVal(pl, 'metrics.volume_cbm');
  const volDiff  = Math.abs(plVolume - blVolume).toFixed(3);

  let volumeStatus;
  if      (blVolume === 0 && plVolume === 0) volumeStatus = '⚠️ UNAVAILABLE (missing on both BL and PL)';
  else if (blVolume === 0)                   volumeStatus = '⚠️ UNAVAILABLE (missing on BL)';
  else if (plVolume === 0)                   volumeStatus = '⚠️ UNAVAILABLE (missing on PL)';
  else if (parseFloat(volDiff) > 0.1)        volumeStatus = `❌ DISCREPANCY (${volDiff}cbm variance)`;
  else                                        volumeStatus = '✅ MATCH';

  // ── Check 4: Packaging ────────────────────────────────────
  const blPallets = getVal(bl, 'metrics.pallet_count');
  const plPallets = getVal(pl, 'metrics.pallet_count');
  const blCartons = getVal(bl, 'metrics.carton_count');
  const plCartons = getVal(pl, 'metrics.carton_count');
  const blPieces  = getVal(bl, 'metrics.piece_count');
  const plPieces  = getVal(pl, 'metrics.piece_count');

  const isPalletized = blPallets > 0;
  const isLoose      = blCartons > 0;

  let packagingStatus;

  // Cross-reference check: BL cartons match PL pieces (or PL cartons+pieces)
  // This catches the case where PL expresses total units as pieces rather than cartons
  const blCartonsMatchPlPieces    = isLoose && plPieces > 0 && blCartons === plPieces;
  const blCartonsMatchPlTotal     = isLoose && plPieces > 0 && plCartons > 0 && blCartons === (plCartons + plPieces);
  const blPalletsMatchPlPieces    = isPalletized && plPieces > 0 && blPallets === plPieces;

  if (isPalletized) {
    if (plPallets === 0 && blPalletsMatchPlPieces) {
      packagingStatus = `⚠️ REVIEW REQUIRED — BL pallets (${blPallets}) matches PL pieces (${plPieces}): possible unit label mismatch`;
    } else if (plPallets === 0) {
      packagingStatus = '⚠️ UNAVAILABLE (palletized shipment — pallet count missing on PL)';
    } else if (blPallets !== plPallets) {
      packagingStatus = `❌ DISCREPANCY — Pallets: PL ${plPallets} vs BL ${blPallets}`;
    } else {
      packagingStatus = `✅ MATCH (palletized — ${blPallets} pallets)`;
    }
    if (blPieces > 0) {
      if      (plPieces === 0)        packagingStatus += ' | ⚠️ Loose pieces: missing on PL';
      else if (blPieces !== plPieces)  packagingStatus += ` | ❌ Loose pieces: PL ${plPieces} vs BL ${blPieces}`;
      else                             packagingStatus += ` | ✅ Loose pieces: ${blPieces} match`;
    }
  } else if (isLoose) {
    if (blCartonsMatchPlPieces) {
      packagingStatus = `⚠️ REVIEW REQUIRED — BL cartons (${blCartons}) matches PL pieces (${plPieces}): possible unit label mismatch on PL`;
    } else if (blCartonsMatchPlTotal) {
      packagingStatus = `⚠️ REVIEW REQUIRED — BL cartons (${blCartons}) matches PL cartons+pieces (${plCartons}+${plPieces}=${plCartons+plPieces}): possible split counting on PL`;
    } else if (plCartons === 0) {
      packagingStatus = '⚠️ UNAVAILABLE (loose shipment — carton count missing on PL)';
    } else if (blCartons !== plCartons) {
      packagingStatus = `❌ DISCREPANCY — Cartons: PL ${plCartons} vs BL ${blCartons}`;
    } else {
      packagingStatus = `✅ MATCH (loose — ${blCartons} cartons)`;
    }
  } else {
    packagingStatus = '⚠️ UNAVAILABLE (could not determine shipment type from BL)';
  }

  // ── Check 5: Description ──────────────────────────────────
  const descResult = descriptionOverlap(bl.product, pl.product);
  const descStatus = `${descResult.status} (${descResult.detail})`;

  // ── Check 6: Per-container subtotals ──────────────────────
  // Only run if there are 2+ valid containers on the BL
  let containerStatus;
  if (bl.containers.length <= 1) {
    containerStatus = `⚠️ N/A (single container shipment — per-container check not applicable)`;
  } else if (pl.containers.length === 0) {
    containerStatus = '⚠️ UNAVAILABLE (no container breakdown on PL)';
  } else {
    const plMap = {};
    for (const c of pl.containers) {
      plMap[(c.container_number || '').trim().toUpperCase()] = c;
    }
    const errors = [], warnings = [], matched = [];
    for (const blC of bl.containers) {
      const num = (blC.container_number || '').trim().toUpperCase();
      const plC = plMap[num];
      if (!plC) { warnings.push(`${num}: on BL but not found on PL`); continue; }

      const wDiff = Math.abs((plC.gross_weight_kg || 0) - (blC.gross_weight_kg || 0)).toFixed(2);
      const vDiff = Math.abs((plC.volume_cbm      || 0) - (blC.volume_cbm      || 0)).toFixed(3);
      const blPkg = blC.package_count || 0;
      const plPkg = plC.package_count || 0;
      const pDiff = plPkg - blPkg;

      const cErrors = [];
      if (parseFloat(wDiff) > 1.0) cErrors.push(`weight PL ${plC.gross_weight_kg}kg vs BL ${blC.gross_weight_kg}kg`);
      if (parseFloat(vDiff) > 0.1)  cErrors.push(`volume PL ${plC.volume_cbm}cbm vs BL ${blC.volume_cbm}cbm`);

      if (pDiff !== 0) {
        const ratio = blPkg > 0 ? plPkg / blPkg : 0;
        const isLikelyCartonMix = blPkg > 0 && Number.isInteger(ratio) && ratio >= 2;
        if (isLikelyCartonMix) {
          cErrors.push(`packages PL ${plPkg} vs BL ${blPkg} — ⚠️ possible carton/pallet mix (${ratio}x ratio, verify)`);
        } else {
          cErrors.push(`packages PL ${plPkg} vs BL ${blPkg}`);
        }
      }

      if (cErrors.length > 0) errors.push(`${num}: ${cErrors.join(', ')}`);
      else matched.push(num);
    }
    for (const plC of pl.containers) {
      const num = (plC.container_number || '').trim().toUpperCase();
      if (!bl.containers.find(b => (b.container_number || '').trim().toUpperCase() === num))
        warnings.push(`${num}: on PL but not found on BL`);
    }
    if (errors.length > 0) {
      containerStatus = `❌ DISCREPANCY (${errors.join(' | ')})`;
      if (warnings.length > 0) containerStatus += ` | ⚠️ ${warnings.join(', ')}`;
    } else if (warnings.length > 0) {
      containerStatus = `⚠️ PARTIAL (${warnings.join(', ')})`;
    } else {
      containerStatus = `✅ MATCH (${matched.length} container${matched.length !== 1 ? 's' : ''} verified)`;
    }
  }

  // ── Check 7: Incoterm ─────────────────────────────────────
  // Trade terms without a port (FOB, CIF, EXW etc) are not comparable to a port name
  const TRADE_TERMS = new Set(['FOB','CIF','CFR','EXW','DDP','DAP','FCA','CPT','CIP','DPU']);
  const blIncotermIsPort  = bl.incoterm && !TRADE_TERMS.has(bl.incoterm);
  const plIncotermIsPort  = pl.incoterm && !TRADE_TERMS.has(pl.incoterm);
  const blIncotermIsTerm  = TRADE_TERMS.has(bl.incoterm);
  const plIncotermIsTerm  = TRADE_TERMS.has(pl.incoterm);

  let incotermStatus;
  if (!bl.incoterm && !pl.incoterm) {
    incotermStatus = '⚠️ UNAVAILABLE (missing on both BL and PL)';
  } else if (!bl.incoterm) {
    incotermStatus = '⚠️ UNAVAILABLE (missing on BL)';
  } else if (!pl.incoterm) {
    incotermStatus = '⚠️ UNAVAILABLE (missing on PL)';
  } else if (blIncotermIsTerm && plIncotermIsPort) {
    incotermStatus = `⚠️ REVIEW REQUIRED — BL has trade term (${bl.incoterm}), PL has port (${pl.incoterm}): confirm ${bl.incoterm} ${pl.incoterm}`;
  } else if (blIncotermIsPort && plIncotermIsTerm) {
    incotermStatus = `⚠️ REVIEW REQUIRED — BL has port (${bl.incoterm}), PL has trade term (${pl.incoterm}): confirm ${pl.incoterm} ${bl.incoterm}`;
  } else if (bl.incoterm.includes(pl.incoterm) || pl.incoterm.includes(bl.incoterm)) {
    incotermStatus = `✅ MATCH (${bl.incoterm})`;
  } else {
    incotermStatus = `❌ DISCREPANCY (BL: ${bl.incoterm} vs PL: ${pl.incoterm})`;
  }

  // ── Overall ───────────────────────────────────────────────
  const allChecks = [
    { key: '✓1 Consignor',   status: consignorStatus  },
    { key: '✓2 Consignee',   status: consigneeStatus  },
    { key: '✓3 Weight',      status: weightStatus     },
    { key: '✓3b Volume',     status: volumeStatus     },
    { key: '✓4 Packaging',   status: packagingStatus  },
    { key: '✓5 Description', status: descStatus       },
    { key: '✓6 Containers',  status: containerStatus  },
    { key: '✓7 Incoterm',    status: incotermStatus   },
  ];

  const failures = allChecks.filter(c => c.status.startsWith('❌'));
  const partials = allChecks.filter(c => c.status.startsWith('⚠️'));
  const passes   = allChecks.filter(c => c.status.startsWith('✅'));

  let overallStatus;
  if (failures.length > 0) {
    const failList = failures.map(c => c.key).join(', ');
    const warnList = partials.length > 0 ? ` | ⚠️ PARTIAL: ${partials.map(c => c.key).join(', ')}` : '';
    overallStatus = failures.length === 1
      ? `❌ DISCREPANCY — ${failList}${warnList}`
      : `❌ ${failures.length} DISCREPANCIES — ${failList}${warnList}`;
  } else if (partials.length > 0) {
    const warnList = partials.map(c => c.key).join(', ');
    overallStatus = partials.length === 1
      ? `⚠️ PARTIAL — ${warnList}`
      : `⚠️ PARTIAL (${partials.length} checks) — ${warnList}`;
  } else {
    overallStatus = `✅ CLEAR — all ${passes.length} checks passed`;
  }

  // ── Audit date: YYYY-MM-DD HH:MM ──────────────────────────
  const now = new Date();
  const auditDate = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')} ${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;

  return {
    json: {
      // ── 📁 Reference ───────────────────────────
      Parent_ID:               input.Parent_ID       || "N/A",
      Match_ID:                input.Match_ID        || "N/A",
      "Folder name":           input["Folder name"]  || "N/A",
      Audit_Date:              auditDate,
      Runtime_Seconds:         runtime,

      // ── 📦 Shipment ────────────────────────────
      "Booking#":              input["Booking#"]     || "N/A",
      "Booking type":          input["Booking type"] || "N/A",

      // ── 🔎 Overall ─────────────────────────────
      Overall_Status:          overallStatus,

      // ── ✓1 Consignor ───────────────────────────
      Check1_Consignor:        consignorStatus,
      BL_Consignor_Name:       blConsignorName,
      PL_Consignor_Name:       plConsignorName,
      BL_Consignor_Address:    blConsignorAddress,
      PL_Consignor_Address:    plConsignorAddress,

      // ── ✓2 Consignee ───────────────────────────
      Check2_Consignee:        consigneeStatus,
      BL_Consignee_Name:       blConsigneeName,
      PL_Consignee_Name:       plConsigneeName,
      BL_Consignee_Address:    blConsigneeAddress,
      PL_Consignee_Address:    plConsigneeAddress,

      // ── ✓3 Weight ──────────────────────────────
      Check3_Weight:           weightStatus,
      BL_Weight:               blWeight,
      PL_Weight:               plWeight,
      Weight_Variance:         weightDiff,

      // ── ✓3b Volume ─────────────────────────────
      Check3_Volume:           volumeStatus,
      BL_Volume:               blVolume,
      PL_Volume:               plVolume,
      Volume_Variance:         volDiff,

      // ── ✓4 Packaging ───────────────────────────
      Check4_Packaging:        packagingStatus,
      BL_Pallets:              blPallets,
      PL_Pallets:              plPallets,
      BL_Cartons:              blCartons,
      PL_Cartons:              plCartons,
      BL_Pieces:               blPieces,
      PL_Pieces:               plPieces,

      // ── ✓5 Description ─────────────────────────
      Check5_Description:      descStatus,
      BL_Product:              bl.product,
      PL_Product:              pl.product,

      // ── ✓6 Containers ──────────────────────────
      Check6_Containers:       containerStatus,
      BL_Incoterm:             bl.incoterm || "NOT_FOUND",
      PL_Incoterm:             pl.incoterm || "NOT_FOUND",

      // ── ✓7 Incoterm ────────────────────────────
      Check7_Incoterm:         incotermStatus,

      // ── ⚙ Meta ────────────────────────────────
      BL_Tokens_Used:          input.BL_tokens_used || 0,
      PL_Tokens_Used:          input.PL_tokens_used || 0,
    }
  };
});

for (const item of items) {
  const rawContent = item.json.BL_content || "";
  const cleanJsonString = rawContent.replace(/```json|```/g, "").trim();

  if (cleanJsonString) {
    try {
      const parsedData = JSON.parse(cleanJsonString);

      item.json = {
        Match_ID:             item.json.Match_ID,
        Parent_ID:            item.json.Parent_ID,
        "Booking#":           item.json["Booking#"],
        "Booking type":       item.json["Booking type"],
        "Folder name":        item.json["Folder name"],
        Document_ID:          item.json.Document_ID,
        Document_name:        item.json.Document_name,
        BL_tokens_used:       item.json.BL_tokens_used || 0,

        BL_factory:           parsedData.factory           || {},
        BL_consignee:         parsedData.consignee         || {},
        BL_incoterm_location: parsedData.incoterm_location || "NOT_FOUND",
        BL_logistics_metrics: parsedData.logistics_metrics || {},
        BL_containers:        parsedData.containers        || [],
        BL_cargo_description: parsedData.cargo_description || "NOT_FOUND",
        BL_document_type:     parsedData.document_type     || "HBL",
      };

    } catch (error) {
      item.json.error             = "Invalid JSON from Gemini (BL)";
      item.json.raw_content_debug = cleanJsonString;
    }
  }
}

return items;

const boundary = 'n8n_boundary';
// Use the helper to get the binary data correctly
const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');

const header = Buffer.from(
  `--${boundary}\r\n` +
  `Content-Type: application/json; charset=UTF-8\r\n\r\n` +
  `{"mimeType": "application/vnd.google-apps.spreadsheet"}\r\n\r\n` +
  `--${boundary}\r\n` +
  `Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\r\n\r\n`, 
  'utf-8'
);

const footer = Buffer.from(`\r\n--${boundary}--`, 'utf-8');
const combinedBuffer = Buffer.concat([header, binaryData, footer]);

return [
  {
    json: $input.item.json,
    binary: {
      data: {
        data: combinedBuffer.toString('base64'),
        mimeType: `multipart/related; boundary=${boundary}`,
        fileName: 'upload.bin'
      }
    }
  }
];

for (const item of items) {
  try {
    const Match_ID      = item.json.Match_ID;
    const Parent_ID     = item.json.Parent_ID;
    const Document_ID   = item.json.Document_ID;
    const Document_name = item.json.Document_name;
    const Booking       = item.json["Booking#"];
    const BookingType   = item.json["Booking type"];
    const FolderName    = item.json["Folder name"];

    const rawContent      = item.json.content?.parts?.[0]?.text || "";
    const cleanJsonString = rawContent.replace(/```json|```/g, "").trim();

    if (cleanJsonString) {
      const parsedData = JSON.parse(cleanJsonString);

      item.json = {
        Match_ID:             Match_ID,
        Parent_ID:            Parent_ID,
        "Booking#":           Booking,
        "Booking type":       BookingType,
        "Folder name":        FolderName,
        Document_ID:          Document_ID,
        Document_name:        Document_name,
        PL_tokens_used:       item.json.usageMetadata?.totalTokenCount ||
                              item.json.usageMetadata?.promptTokenCount || 0,

        PL_factory:           parsedData.factory           || {},
        PL_consignee:         parsedData.consignee         || {},
        PL_incoterm_location: parsedData.incoterm_location || "NOT_FOUND",
        PL_logistics_metrics: parsedData.logistics_metrics || {},
        PL_containers:        parsedData.containers        || [],
        PL_cargo_description: parsedData.cargo_description || "NOT_FOUND",
        PL_document_type:     parsedData.document_type     || "Packing List",
      };
    }
  } catch (error) {
    item.json.error         = "Failed to parse Gemini output (PL)";
    item.json.error_details = error.message;
  }
}

return items;
